398: // Repair attempts to repair the WAL based on the error.
399: // It discards all data after the corruption.
400: func (w *WL) Repair(origErr error) error {
401: 	// We could probably have a mode that only discards torn records right around
402: 	// the corruption to preserve as data much as possible.
403: 	// But that's not generally applicable if the records have any kind of causality.
404: 	// Maybe as an extra mode in the future if mid-WAL corruptions become
405: 	// a frequent concern.
406: 	var cerr *CorruptionErr
407: 	if !errors.As(origErr, &cerr) {
408: 		return fmt.Errorf("cannot handle error: %w", origErr)
409: 	}
410: 	if cerr.Segment < 0 {
411: 		return errors.New("corruption error does not specify position")
412: 	}
413: 	w.logger.Warn("Starting corruption repair",
414: 		"segment", cerr.Segment, "offset", cerr.Offset)
415: 
416: 	// All segments behind the corruption can no longer be used.
417: 	segs, err := listSegments(w.Dir())
418: 	if err != nil {
419: 		return fmt.Errorf("list segments: %w", err)
420: 	}
421: 	w.logger.Warn("Deleting all segments newer than corrupted segment", "segment", cerr.Segment)
422: 
423: 	for _, s := range segs {
424: 		if w.segment.i == s.index {
425: 			// The active segment needs to be removed,
426: 			// close it first (Windows!). Can be closed safely
427: 			// as we set the current segment to repaired file
428: 			// below.
429: 			if err := w.segment.Close(); err != nil {
430: 				return fmt.Errorf("close active segment: %w", err)
431: 			}
432: 		}
433: 		if s.index <= cerr.Segment {
434: 			continue
435: 		}
436: 		if err := os.Remove(filepath.Join(w.Dir(), s.name)); err != nil {
437: 			return fmt.Errorf("delete segment:%v: %w", s.index, err)
438: 		}
439: 	}
440: 	// Regardless of the corruption offset, no record reaches into the previous segment.
441: 	// So we can safely repair the WAL by removing the segment and re-inserting all
442: 	// its records up to the corruption.
443: 	w.logger.Warn("Rewrite corrupted segment", "segment", cerr.Segment)
444: 
445: 	fn := SegmentName(w.Dir(), cerr.Segment)
446: 	tmpfn := fn + ".repair"
447: 
448: 	if err := fileutil.Rename(fn, tmpfn); err != nil {
449: 		return err
450: 	}
