528: // nextSegment creates the next segment and closes the previous one.
529: // It returns the file number of the new file.
530: func (w *WL) nextSegment(async bool) (int, error) {
531: 	if w.closed {
532: 		return 0, errors.New("wlog is closed")
533: 	}
534: 
535: 	// Only flush the current page if it actually holds data.
536: 	if w.page.alloc > 0 {
537: 		if err := w.flushPage(true); err != nil {
538: 			return 0, err
539: 		}
540: 	}
541: 	next, err := CreateSegment(w.Dir(), w.segment.Index()+1)
542: 	if err != nil {
543: 		return 0, fmt.Errorf("create new segment file: %w", err)
544: 	}
545: 	prev := w.segment
546: 	if err := w.setSegment(next); err != nil {
547: 		return 0, err
548: 	}
549: 
550: 	// Don't block further writes by fsyncing the last segment.
551: 	f := func() {
552: 		if err := w.fsync(prev); err != nil {
553: 			w.logger.Error("sync previous segment", "err", err)
554: 		}
555: 		if err := prev.Close(); err != nil {
556: 			w.logger.Error("close previous segment", "err", err)
557: 		}
558: 	}
559: 	if async {
560: 		w.actorc <- f
561: 	} else {
562: 		f()
563: 	}
564: 	return next.Index(), nil
565: }
