567: func (w *WL) setSegment(segment *Segment) error {
568: 	w.segment = segment
569: 
570: 	// Correctly initialize donePages.
571: 	stat, err := segment.Stat()
572: 	if err != nil {
573: 		return err
574: 	}
575: 	w.donePages = int(stat.Size() / pageSize)
576: 	w.metrics.currentSegment.Set(float64(segment.Index()))
577: 	return nil
578: }
