580: // flushPage writes the new contents of the page to disk. If no more records will fit into
581: // the page, the remaining bytes will be set to zero and a new page will be started.
582: // If forceClear is true, this is enforced regardless of how many bytes are left in the page.
583: func (w *WL) flushPage(forceClear bool) error {
584: 	w.metrics.pageFlushes.Inc()
585: 
586: 	p := w.page
587: 	shouldClear := forceClear || p.full()
588: 
589: 	// No more data will fit into the page or an implicit clear.
590: 	// Enqueue and clear it.
591: 	if shouldClear {
592: 		p.alloc = pageSize // Write till end of page.
593: 	}
594: 
595: 	n, err := w.segment.Write(p.buf[p.flushed:p.alloc])
596: 	if err != nil {
597: 		p.flushed += n
598: 		return err
599: 	}
600: 	p.flushed += n
601: 
602: 	// We flushed an entire page, prepare a new one.
603: 	if shouldClear {
604: 		p.reset()
605: 		w.donePages++
606: 		w.metrics.pageCompletions.Inc()
607: 	}
608: 	return nil
609: }
