611: // First Byte of header format:
612: //
613: //	[3 bits unallocated] [1 bit zstd compression flag] [1 bit snappy compression flag] [3 bit record type ]
614: const (
615: 	snappyMask  = 1 << 3
616: 	zstdMask    = 1 << 4
617: 	recTypeMask = snappyMask - 1
618: )
619: 
620: type recType uint8
621: 
622: const (
623: 	recPageTerm recType = 0 // Rest of page is empty.
624: 	recFull     recType = 1 // Full record.
625: 	recFirst    recType = 2 // First fragment of a record.
626: 	recMiddle   recType = 3 // Middle fragments of a record.
627: 	recLast     recType = 4 // Final fragment of a record.
628: )
629: 
630: func recTypeFromHeader(header byte) recType {
631: 	return recType(header & recTypeMask)
632: }
633: 
634: func (t recType) String() string {
635: 	switch t {
636: 	case recPageTerm:
637: 		return "zero"
638: 	case recFull:
639: 		return "full"
640: 	case recFirst:
641: 		return "first"
642: 	case recMiddle:
643: 		return "middle"
644: 	case recLast:
645: 		return "last"
646: 	default:
647: 		return "<invalid>"
648: 	}
649: }
