756: func (*Encoder) EncodeExemplarsIntoBuffer(exemplars []RefExemplar, buf *encoding.Encbuf) {
757: 	// Store base timestamp and base reference number of first sample.
758: 	// All samples encode their timestamp and ref as delta to those.
759: 	first := exemplars[0]
760: 
761: 	buf.PutBE64(uint64(first.Ref))
762: 	buf.PutBE64int64(first.T)
763: 
764: 	for _, ex := range exemplars {
765: 		buf.PutVarint64(int64(ex.Ref) - int64(first.Ref))
766: 		buf.PutVarint64(ex.T - first.T)
767: 		buf.PutBE64(math.Float64bits(ex.V))
768: 		EncodeLabels(buf, ex.Labels)
769: 	}
770: }
