172: // WL is a write log that stores records in segment files.
173: // It must be read from start to end once before logging new data.
174: // If an error occurs during read, the repair procedure must be called
175: // before it's safe to do further writes.
176: //
177: // Segments are written to in pages of 32KB, with records possibly split
178: // across page boundaries.
179: // Records are never split across segments to allow full segments to be
180: // safely truncated. It also ensures that torn writes never corrupt records
181: // beyond the most recent segment.
182: type WL struct {
183: 	dir         string
184: 	logger      *slog.Logger
185: 	segmentSize int
186: 	mtx         sync.RWMutex
187: 	segment     *Segment // Active segment.
188: 	donePages   int      // Pages written to the segment.
189: 	page        *page    // Active page.
190: 	stopc       chan chan struct{}
191: 	actorc      chan func()
192: 	closed      bool // To allow calling Close() more than once without blocking.
193: 	compress    compression.Type
194: 	cEnc        compression.EncodeBuffer
195: 
196: 	WriteNotified WriteNotified
197: 
198: 	metrics *wlMetrics
199: }
