{"content":"800: func (w *WL) Truncate(i int) (err error) {
801: 	w.metrics.truncateTotal.Inc()
802: 	defer func() {
803: 		if err != nil {
804: 			w.metrics.truncateFail.Inc()
805: 		}
806: 	}()
807: 	refs, err := listSegments(w.Dir())
808: 	if err != nil {
809: 		return err
810: 	}
811: 	for _, r := range refs {
812: 		if r.index >= i {
813: 			break
814: 		}
815: 		if err = os.Remove(filepath.Join(w.Dir(), r.name)); err != nil {
816: 			return err
817: 		}
818: 	}
819: 	return nil
820: }
821: 
822: func (w *WL) fsync(f *Segment) error {
823: 	start := time.Now()
824: 	err := f.Sync()
825: 	w.metrics.fsyncDuration.Observe(time.Since(start).Seconds())
826: 	return err
827: }
828: 
829: // Sync forces a file sync on the current write log segment. This function is meant
830: // to be used only on tests due to different behaviour on Operating Systems
831: // like windows and linux.
832: func (w *WL) Sync() error {
833: 	return w.fsync(w.segment)
834: }
835: 
836: // Close flushes all writes and closes active segment.
837: func (w *WL) Close() (err error) {
838: 	w.mtx.Lock()
839: 	defer w.mtx.Unlock()
840: 
841: 	if w.closed {
842: 		return errors.New("wlog already closed")
843: 	}
844: 
845: 	if w.segment == nil {
846: 		w.closed = true
847: 		return nil
848: 	}
849: 
850: 	// Flush the last page and zero out all its remaining size.
851: 	// We must not flush an empty page as it would falsely signal
852: 	// the segment is done if we start writing to it again after opening.
853: 	if w.page.alloc > 0 {
854: 		if err := w.flushPage(true); err != nil {
855: 			return err
856: 		}
857: 	}
858: 
859: 	donec := make(chan struct{})
860: 	w.stopc <- donec
861: 	<-donec
862: 
863: 	if err = w.fsync(w.segment); err != nil {
864: 		w.logger.Error("sync previous segment", "err", err)
865: 	}
866: 	if err := w.segment.Close(); err != nil {
867: 		w.logger.Error("close previous segment", "err", err)
868: 	}
869: 
870: 	w.metrics.Unregister()
871: 	w.closed = true
872: 	return nil
873: }
874: 
875: // Segments returns the range [first, n] of currently existing segments.
876: // If no segments are found, first and n are -1.
877: func Segments(wlDir string) (first, last int, err error) {
878: 	refs, err := listSegments(wlDir)
879: 	if err != nil {
880: 		return 0, 0, err
881: 	}
882: 	if len(refs) == 0 {
883: 		return -1, -1, nil
884: 	}
885: 	return refs[0].index, refs[len(refs)-1].index, nil
886: }
887: 
888: type segmentRef struct {
889: 	name  string
890: 	index int
891: }
892: 
893: func listSegments(dir string) (refs []segmentRef, err error) {
894: 	files, err := os.ReadDir(dir)
895: 	if err != nil {
896: 		return nil, err
897: 	}
898: 	for _, f := range files {
899: 		fn := f.Name()
900: 		k, err := strconv.Atoi(fn)
901: 		if err != nil {
902: 			continue
903: 		}
904: 		refs = append(refs, segmentRef{name: fn, index: k})
905: 	}
906: 	slices.SortFunc(refs, func(a, b segmentRef) int {
907: 		return a.index - b.index
908: 	})
909: 	for i := 0; i < len(refs)-1; i++ {
910: 		if refs[i].index+1 != refs[i+1].index {
911: 			return nil, errors.New("segments are not sequential")
912: 		}
913: 	}
914: 	return refs, nil
915: }
916: 
917: // SegmentRange groups segments by the directory and the first and last index it includes.
918: type SegmentRange struct {
919: 	Dir         string
920: 	First, Last int
921: }
922: 
923: // NewSegmentsReader returns a new reader over all segments in the directory.
924: func NewSegmentsReader(dir string) (io.ReadCloser, error) {
925: 	return NewSegmentsRangeReader(SegmentRange{dir, -1, -1})
926: }
927: 
928: // NewSegmentsRangeReader returns a new reader over the given WAL segment ranges.
929: // If first or last are -1, the range is open on the respective end.
930: func NewSegmentsRangeReader(sr ...SegmentRange) (io.ReadCloser, error) {
931: 	var segs []*Segment
932: 
933: 	for _, sgmRange := range sr {
934: 		refs, err := listSegments(sgmRange.Dir)
935: 		if err != nil {
936: 			return nil, fmt.Errorf("list segment in dir:%v: %w", sgmRange.Dir, err)
937: 		}
938: 
939: 		for _, r := range refs {
940: 			if sgmRange.First >= 0 && r.index < sgmRange.First {
941: 				continue
942: 			}
943: 			if sgmRange.Last >= 0 && r.index > sgmRange.Last {
944: 				break
945: 			}
946: 			s, err := OpenReadSegment(filepath.Join(sgmRange.Dir, r.name))
947: 			if err != nil {
948: 				return nil, fmt.Errorf("open segment:%v in dir:%v: %w", r.name, sgmRange.Dir, err)
949: 			}
950: 			segs = append(segs, s)
